import { tags } from 'decantr/tags';
import { createSignal, createEffect } from 'decantr/state';
import { css } from 'decantr/css';
import { icon } from 'decantr/components';

code.example:
function SlashCommand({ position, query, onSelect, onClose }) {
  const { div, span, button, input, kbd } = tags;
  const [selectedIndex, setSelectedIndex] = createSignal(0);

  const commands = [
    { category: 'Text', items: [
      { id: 'paragraph', name: 'Text', description: 'Plain text block', icon: 'type', shortcut: null },
      { id: 'heading1', name: 'Heading 1', description: 'Large section heading', icon: 'heading-1', shortcut: '# ' },
      { id: 'heading2', name: 'Heading 2', description: 'Medium section heading', icon: 'heading-2', shortcut: '## ' },
      { id: 'heading3', name: 'Heading 3', description: 'Small section heading', icon: 'heading-3', shortcut: '### ' },
    ]},
    { category: 'Lists', items: [
      { id: 'bullet-list', name: 'Bulleted list', description: 'Unordered list items', icon: 'list', shortcut: '- ' },
      { id: 'numbered-list', name: 'Numbered list', description: 'Ordered list items', icon: 'list-ordered', shortcut: '1. ' },
      { id: 'todo-list', name: 'To-do list', description: 'Checklist items', icon: 'check-square', shortcut: '[] ' },
    ]},
    { category: 'Media', items: [
      { id: 'image', name: 'Image', description: 'Upload or embed image', icon: 'image', shortcut: null },
      { id: 'video', name: 'Video', description: 'Embed video', icon: 'video', shortcut: null },
      { id: 'file', name: 'File', description: 'Attach a file', icon: 'paperclip', shortcut: null },
    ]},
    { category: 'Advanced', items: [
      { id: 'code', name: 'Code block', description: 'Syntax highlighted code', icon: 'code', shortcut: '```' },
      { id: 'quote', name: 'Quote', description: 'Blockquote', icon: 'quote', shortcut: '> ' },
      { id: 'divider', name: 'Divider', description: 'Horizontal separator', icon: 'minus', shortcut: '---' },
      { id: 'callout', name: 'Callout', description: 'Highlighted info box', icon: 'alert-circle', shortcut: null },
      { id: 'table', name: 'Table', description: 'Data table', icon: 'table', shortcut: null },
    ]}
  ];

  const flatCommands = commands.flatMap(c => c.items);
  const filteredCommands = query 
    ? flatCommands.filter(c => 
        c.name.toLowerCase().includes(query.toLowerCase()) ||
        c.description.toLowerCase().includes(query.toLowerCase())
      )
    : null;

  const displayCommands = filteredCommands || flatCommands;

  const handleKeyDown = (e) => {
    const max = displayCommands.length - 1;
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      setSelectedIndex(Math.min(selectedIndex() + 1, max));
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      setSelectedIndex(Math.max(selectedIndex() - 1, 0));
    } else if (e.key === 'Enter') {
      e.preventDefault();
      displayCommands[selectedIndex()] && onSelect(displayCommands[selectedIndex()]);
    } else if (e.key === 'Escape') {
      onClose();
    }
  };

  createEffect(() => {
    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  });

  const renderCommand = (cmd, globalIndex) => button({
    class: css(`_flex _aic _gap3 _p2 _wfull _textleft _r1 ${globalIndex === selectedIndex() ? '_bg[var(--primary)/10]' : '_hover:bg[var(--surface-raised)]'}`),
    onclick: () => onSelect(cmd),
    onmouseenter: () => setSelectedIndex(globalIndex)
  },
    div({ class: css('_w8 _h8 _rfull _bg[var(--surface-raised)] _flex _aic _jcc') },
      icon(cmd.icon, { size: '16' })
    ),
    div({ class: css('_flex _col _flex1') },
      span({ class: css('_textsm _fontmedium') }, cmd.name),
      span({ class: css('_textxs _fgmuted') }, cmd.description)
    ),
    cmd.shortcut ? kbd({ class: css('_textxs _fgmuted _px1.5 _py0.5 _bg[var(--surface-raised)] _r1 _font[mono]') }, cmd.shortcut) : null
  );

  let globalIndex = 0;

  return div({
    class: css('_absolute _bg[var(--surface)] _shadow _r2 _border _w[320px] _max-h[400px] _overflow[auto] _z[100]'),
    style: `top: ${position.y}px; left: ${position.x}px`
  },
    // Show filtered results or categorized list
    filteredCommands ? div({ class: css('_p2') },
      filteredCommands.length > 0 
        ? filteredCommands.map((cmd, i) => renderCommand(cmd, i))
        : div({ class: css('_py4 _textcenter _textsm _fgmuted') }, 'No commands found')
    ) : commands.map(category => div({ class: css('_p2') },
      span({ class: css('_textxs _fgmuted _fontmedium _uppercase _tracking[0.05em] _px2') }, category.category),
      div({ class: css('_flex _col _mt1') },
        ...category.items.map(cmd => {
          const el = renderCommand(cmd, globalIndex);
          globalIndex++;
          return el;
        })
      )
    ))
  );
}

