function FilteredSlashCommand({ position, query, commands, onSelect }) {
  const { div, span, button } = tags;
  const [selectedIndex, setSelectedIndex] = createSignal(0);

  const filtered = commands.filter(c => 
    c.name.toLowerCase().includes(query.toLowerCase())
  ).slice(0, 10);

  return div({
    class: css('_absolute _bg[var(--surface)] _shadow _r1 _border _w[280px] _z[100] _py1'),
    style: `top: ${position.y}px; left: ${position.x}px`
  },
    filtered.length > 0 ? filtered.map((cmd, i) =>
      button({
        class: css(`_flex _aic _gap2 _px3 _py2 _wfull _textleft ${i === selectedIndex() ? '_bg[var(--surface-raised)]' : ''}`),
        onclick: () => onSelect(cmd),
        onmouseenter: () => setSelectedIndex(i)
      },
        icon(cmd.icon, { size: '16' }),
        span({ class: css('_textsm') }, cmd.name)
      )
    ) : div({ class: css('_px3 _py4 _textsm _fgmuted _textcenter') }, 'No commands found')
  );
}

